class Leyenda {
  final String id;
  final String titulo;
  final String departamento;
  final String descripcionCorta;
  final String descripcionLarga;
  final String imagen;
  final String origen;
  final int nivelDeTerror;
  final String ritualDeProteccion;
  final String horaAparicion;
  final String habitat;
  final String? userId;

  Leyenda({
    required this.id,
    required this.titulo,
    required this.departamento,
    required this.descripcionCorta,
    required this.descripcionLarga,
    required this.imagen,
    required this.origen,
    this.nivelDeTerror = 3,
    this.ritualDeProteccion = 'No se conoce un ritual específico de protección. Mantente alerta.',
    this.horaAparicion = 'Durante la noche',
    this.habitat = 'Desconocido',
    this.userId,
  });
}
